import express from "express";
const { Router } = express;
import { adminAuth } from "../../middleware/adminAuth.js";
import { managerAccess } from "../../middleware/managerAccess.js";
import { requireManagerPermission } from "../../middleware/requireManagerPermission.js";
import { getBranch, updateBranchVisibility, getHours, updateHours, getConfig, updateDeliveryAreas, updateDeliverySettings, getMenu, updateMenuItem, updateVariantGroup, getOrders, getOrderById, getDashboard, getPromotions, updatePromotions } from "../../controllers/manager/manager.controller.js";
import { getSession } from "../../controllers/manager/managerSession.controller.js";
import { handleMenuImageUpload } from "../../middleware/uploadMenuImage.js";
import { getMenuItemDetail, createCategory, updateCategory, deleteCategory, createMenuItem, updateMenuItemFull, uploadMenuItemImage, clearMenuItemImage, deleteMenuItem, createVariantGroupHandler, updateVariantGroupFull, deleteVariantGroupHandler, createVariantHandler, updateVariantHandler, deleteVariantHandler, createAddOnGroupHandler, updateAddOnGroupHandler, deleteAddOnGroupHandler, createAddOnHandler, updateAddOnHandler, deleteAddOnHandler } from "../../controllers/manager/managerMenu.controller.js";
import { listExtraPresets, createExtraPreset, updateExtraPreset, deleteExtraPreset, addPresetOption, updatePresetOption, deletePresetOption, importDefaultPresets } from "../../controllers/manager/managerExtraPreset.controller.js";
import { exportCustomers, getCustomerOrders, getCustomers, runBranchAutomation } from "../../controllers/manager/branchCustomers.controller.js";
import { getBranchReviews } from "../../controllers/manager/managerReviews.controller.js";
import { ManagerCouponsController } from "../../controllers/manager/managerCoupons.controller.js";
const router = Router();
router.use(adminAuth, managerAccess);
router.get("/session", getSession);
router.get("/branch", getBranch);
router.patch("/branch/status", updateBranchVisibility);
router.get("/dashboard", requireManagerPermission("dashboard"), getDashboard);
router.get("/hours", requireManagerPermission("hours_view"), getHours);
router.put("/hours", requireManagerPermission("hours_edit"), updateHours);
router.get("/config", requireManagerPermission("delivery_view"), getConfig);
router.patch("/config/delivery-areas", requireManagerPermission("delivery_edit"), updateDeliveryAreas);
router.patch("/config/delivery-settings", requireManagerPermission("delivery_edit"), updateDeliverySettings);
router.get("/menu", requireManagerPermission("menu_view"), getMenu);
router.get("/menu/items/:menuItemId/detail", requireManagerPermission("menu_view"), getMenuItemDetail);
router.post("/menu/categories", requireManagerPermission("menu_edit_structure"), createCategory);
router.patch("/menu/categories/:id", requireManagerPermission("menu_edit_structure"), updateCategory);
router.delete("/menu/categories/:id", requireManagerPermission("menu_edit_structure"), deleteCategory);
router.post("/menu/items", requireManagerPermission("menu_edit_structure"), createMenuItem);
router.patch("/menu/items/:id", updateMenuItem);
router.patch("/menu/items/:id/full", requireManagerPermission("menu_edit_structure"), updateMenuItemFull);
router.post("/menu/items/:branchMenuItemId/image", requireManagerPermission("menu_edit_structure"), handleMenuImageUpload, uploadMenuItemImage);
router.delete("/menu/items/:branchMenuItemId/image", requireManagerPermission("menu_edit_structure"), clearMenuItemImage);
router.delete("/menu/branch-items/:branchMenuItemId", requireManagerPermission("menu_edit_structure"), deleteMenuItem);
router.patch("/menu/variant-groups/:groupId", requireManagerPermission("menu_edit_structure"), updateVariantGroup);
router.patch("/menu/variant-groups/:groupId/full", requireManagerPermission("menu_edit_structure"), updateVariantGroupFull);
router.delete("/menu/variant-groups/:groupId", requireManagerPermission("menu_edit_structure"), deleteVariantGroupHandler);
router.post("/menu/items/:menuItemId/variant-groups", requireManagerPermission("menu_edit_structure"), createVariantGroupHandler);
router.post("/menu/variant-groups/:groupId/variants", requireManagerPermission("menu_edit_structure"), createVariantHandler);
router.patch("/menu/variants/:variantId", requireManagerPermission("menu_edit_structure"), updateVariantHandler);
router.delete("/menu/variants/:variantId", requireManagerPermission("menu_edit_structure"), deleteVariantHandler);
router.post("/menu/items/:menuItemId/addon-groups", requireManagerPermission("menu_edit_structure"), createAddOnGroupHandler);
router.patch("/menu/addon-groups/:groupId", requireManagerPermission("menu_edit_structure"), updateAddOnGroupHandler);
router.delete("/menu/addon-groups/:groupId", requireManagerPermission("menu_edit_structure"), deleteAddOnGroupHandler);
router.post("/menu/addon-groups/:groupId/addons", requireManagerPermission("menu_edit_structure"), createAddOnHandler);
router.patch("/menu/addons/:addOnId", requireManagerPermission("menu_edit_structure"), updateAddOnHandler);
router.delete("/menu/addons/:addOnId", requireManagerPermission("menu_edit_structure"), deleteAddOnHandler);
router.get("/menu/extra-presets", requireManagerPermission("menu_view"), listExtraPresets);
router.post("/menu/extra-presets", requireManagerPermission("menu_edit_structure"), createExtraPreset);
router.post("/menu/extra-presets/import-defaults", requireManagerPermission("menu_edit_structure"), importDefaultPresets);
router.patch("/menu/extra-presets/:presetId", requireManagerPermission("menu_edit_structure"), updateExtraPreset);
router.delete("/menu/extra-presets/:presetId", requireManagerPermission("menu_edit_structure"), deleteExtraPreset);
router.post("/menu/extra-presets/:presetId/options", requireManagerPermission("menu_edit_structure"), addPresetOption);
router.patch("/menu/extra-presets/options/:optionId", requireManagerPermission("menu_edit_structure"), updatePresetOption);
router.delete("/menu/extra-presets/options/:optionId", requireManagerPermission("menu_edit_structure"), deletePresetOption);
router.get("/orders", requireManagerPermission("orders"), getOrders);
router.get("/orders/:id", requireManagerPermission("orders"), getOrderById);
router.get("/promotions", requireManagerPermission("offers_view"), getPromotions);
router.patch("/promotions", requireManagerPermission("offers_edit"), updatePromotions);
router.get("/coupon-campaigns", requireManagerPermission("offers_view"), ManagerCouponsController.list);
router.post("/coupon-campaigns", requireManagerPermission("offers_edit"), ManagerCouponsController.create);
router.patch("/coupon-campaigns/:id", requireManagerPermission("offers_edit"), ManagerCouponsController.update);
router.get("/customers", requireManagerPermission("customers_view"), getCustomers);
router.get("/customers/export", requireManagerPermission("customers_export"), exportCustomers);
router.get("/customers/:phone/orders", requireManagerPermission("customers_view"), getCustomerOrders);
router.post("/customers/automation/run", requireManagerPermission("customers_automation"), runBranchAutomation);
router.get("/reviews", requireManagerPermission("reviews_view"), getBranchReviews);
export default router;
